// src/pages/Dashboard.jsx
// Vista principal: balance, totales y resumen por categoría.

import { useTransactions } from '../hooks/useTransactions'
import { formatCurrency }  from '../utils/formatCurrency'
import styles from './Dashboard.module.css'

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠',
  salud: '💊', entretenimiento: '🎬', educación: '📚',
  ropa: '👕', otros: '📦',
}

export default function Dashboard() {
  const { transactions, summary, loading, error } = useTransactions()

  if (loading) return <div className={styles.center}>Cargando dashboard...</div>
  if (error)   return <div className="msg msg--error">{error}</div>

  const recent = transactions.slice(0, 5)

  return (
    <div className={styles.page}>
      <h1 className={styles.title}>Dashboard</h1>

      {/* ── Tarjetas de resumen ─────────────────────── */}
      <div className="grid-3" style={{ marginBottom: 24 }}>
        <div className={`card ${styles.balanceCard}`}>
          <p className="card-title">Balance</p>
          <p className={`${styles.bigNum} ${summary?.balance >= 0 ? styles.pos : styles.neg}`}>
            {formatCurrency(summary?.balance || 0)}
          </p>
        </div>
        <div className="card">
          <p className="card-title">💚 Ingresos</p>
          <p className={`${styles.bigNum} ${styles.pos}`}>{formatCurrency(summary?.totalIncome || 0)}</p>
        </div>
        <div className="card">
          <p className="card-title">🔴 Gastos</p>
          <p className={`${styles.bigNum} ${styles.neg}`}>{formatCurrency(summary?.totalExpense || 0)}</p>
        </div>
      </div>

      <div className="grid-2">
        {/* ── Gastos por categoría ───────────────────── */}
        <div className="card">
          <p className="card-title">Gastos por categoría</p>
          {summary?.byCategory && Object.keys(summary.byCategory).length > 0 ? (
            <ul className={styles.catList}>
              {Object.entries(summary.byCategory)
                .sort((a, b) => b[1] - a[1])
                .map(([cat, amount]) => {
                  const pct = summary.totalExpense
                    ? Math.round((amount / summary.totalExpense) * 100)
                    : 0
                  return (
                    <li key={cat} className={styles.catItem}>
                      <span className={styles.catLabel}>
                        {CATEGORY_EMOJI[cat] || '📦'} {cat.charAt(0).toUpperCase() + cat.slice(1)}
                      </span>
                      <div className={styles.barWrap}>
                        <div className={styles.bar} style={{ width: `${pct}%` }} />
                      </div>
                      <span className={styles.catAmt}>{formatCurrency(amount)}</span>
                    </li>
                  )
                })}
            </ul>
          ) : (
            <p style={{ color: 'var(--text-2)', fontSize: '0.9rem' }}>Sin gastos aún.</p>
          )}
        </div>

        {/* ── Últimas transacciones ──────────────────── */}
        <div className="card">
          <p className="card-title">Últimas transacciones</p>
          {recent.length === 0 ? (
            <p style={{ color: 'var(--text-2)', fontSize: '0.9rem' }}>Sin transacciones aún.</p>
          ) : (
            <ul className={styles.txList}>
              {recent.map((t) => (
                <li key={t.id} className={styles.txItem}>
                  <span className={styles.txEmoji}>{CATEGORY_EMOJI[t.category] || '📦'}</span>
                  <div className={styles.txInfo}>
                    <p className={styles.txDesc}>{t.description}</p>
                    <p className={styles.txMeta}>{t.category}</p>
                  </div>
                  <span className={t.type === 'income' ? styles.pos : styles.neg}>
                    {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                  </span>
                </li>
              ))}
            </ul>
          )}
        </div>
      </div>
    </div>
  )
}
